section.code:
// Subscription conversion
gtag('event', 'generate_lead', {
  currency: 'USD',
  value: 19.00,
  lead_source: 'landing_page'
});

// Trial started
gtag('event', 'start_trial', {
  plan_name: 'Pro',
  trial_duration_days: 14
});

// Upgrade conversion
gtag('event', 'upgrade_plan', {
  from_plan: 'Free',
  to_plan: 'Plus',
  value: 19.00,
  currency: 'USD'
});

// Purchase (always include transaction_id for deduplication)
gtag('event', 'purchase', {
  value: 99.99,
  currency: 'USD',
  transaction_id: 'T12345'
});

// Step 1: Landing page
gtag('event', 'landing_page_view', { page_variant: 'A', utm_source: 'google' });

// Step 2: Pricing view
gtag('event', 'pricing_view', { displayed_plans: ['Free', 'Plus', 'Pro'] });

// Step 3: Checkout started
gtag('event', 'begin_checkout', { selected_plan: 'Plus', value: 19.00, currency: 'USD' });

// Step 4: Payment info entered
gtag('event', 'add_payment_info', { payment_type: 'credit_card' });

// Step 5: Purchase complete
gtag('event', 'purchase', { transaction_id: 'T12345', value: 19.00, currency: 'USD' });
